                ]
            ],
            6 => [
                'text' => 'At a certain company, employees get a medical allowance equal to 5% of their monthly base salary in addition to their monthly base salary. If the total of the monthly base salary and medical allowance is more than 5,000, a 20% tax is deducted from the total. In the program below, the function calculateTotalSal receives the monthly base salary as an argument and returns the monthly total salary after tax deduction. Which of the following is the correct combination of pieces of code to be inserted into A and B in the program? Here, the monthly base salary is a multiple of 100.',
                'image' => '
                    Program:
                    integer: calculateTotalSal(integer: monthlyBaseSal)
                        integer: monthlyTotalSal
                        
                        monthlyTotalSal ← integer part of (monthlyBaseSal × 1.05)
                        
                        if (monthlyTotalSal > A)
                            monthlyTotalSal ← integer part of (monthlyTotalSal × B)
                        endif
                        
                        return monthlyTotalSal
                    
                    Table:
                    +---+-------+-----+
                    |   | A     | B   |
                    +---+-------+-----+
                    | a | 5000  | 0.2 |
                    | b | 5000  | 0.8 |
                    | c | 5250  | 0.2 |
                    | d | 5250  | 0.8 |
                    +---+-------+-----+
                ',
                'choices' => [
                    'a' => '5000, 0.2',
                    'b' => '5000, 0.8',
