            6 => [
                'text' => 'A power company charges electricity bill shown in the table below. Function computeBill receives the number of units used per month as an argument and returns the electricity bill in 1/100 dollars. Which of the following is an appropriate combination of pieces of code to be inserted in A and B in the program?',
                'image' => '
                    Rate table:
                    +--------------------+----------------------+
                    | Units used per month| Per unit cost        |
                    |                    | (in 1/100 US$)       |
                    +--------------------+----------------------+
                    | First 100 units    | 5                    |
                    | Next 200 units     | 10                   |
                    | Over 300 units     | 15                   |
                    +--------------------+----------------------+
                    
                    Program:
                    integer: computeBill(integer: units)
                        integer: bill
                        if (units ≤ 100)
                            bill ← A
                        elseif (units ≤ 300)
                            bill ← 100 × 5 + (units - 100) × 10
                        else
                            bill ← B
                        endif
                        return bill
                    
                    Table:
                    +---+------------------+----------------------------------------------+
                    |   | A                | B                                            |
                    +---+------------------+----------------------------------------------+
                    | a | (units - 100) × 5| 100 × 5 + (units - 100) × 10 + (units - 200) × 15 |
                    | b | (units - 100) × 5| 100 × 5 + 200 × 10 + (units - 300) × 15       |
                    | c | units × 5        | 100 × 5 + (units - 100) × 10 + (units - 200) × 15 |
                    | d | units × 5        | 100 × 5 + 200 × 10 + (units - 300) × 15       |
                    +---+------------------+----------------------------------------------+
                ',
                'choices' => [
                    'a' => '(units - 100) × 5, 100 × 5 + (units - 100) × 10 + (units - 200) × 15',
                    'b' => '(units - 100) × 5, 100 × 5 + 200 × 10 + (units - 300) × 15',
                    'c' => 'units × 5, 100 × 5 + (units - 100) × 10 + (units - 200) × 15',
                    'd' => 'units × 5, 100 × 5 + 200 × 10 + (units - 300) × 15'
                ]
            ],
