            68 => [
                'text' => 'The operating profit when the sales quantity of a product is 700 units is as shown in the table below. When the unit sales price is reduced by 20% to expand sales, the sales quantity increases by 20%. How much, in yen, is the operating profit at this time? Here, the variable cost per one (1) unit of the product does not change.',
                'image' => '
                    Table:
                    +------------------+----------------+
                    | Total sales      | 700,000 yen    |
                    | Cost             |                |
                    |   Variable cost  | 140,000 yen    |
                    |   Fixed cost     | 300,000 yen    |
                    | Operating profit | 260,000 yen    |
                    +------------------+----------------+
                    
                    Current:
                    Sales quantity = 700 units
                    Unit sales price = 700,000 / 700 = 1,000 yen
                    Variable cost per unit = 140,000 / 700 = 200 yen
                    Fixed cost = 300,000 yen
                    
                    New scenario:
                    Unit sales price reduced by 20% → 1,000 × 0.8 = 800 yen
                    Sales quantity increases by 20% → 700 × 1.2 = 840 units
                    New total sales = 840 × 800 = 672,000 yen
                    New variable cost = 840 × 200 = 168,000 yen
                    Fixed cost = 300,000 yen (unchanged)
                    Operating profit = 672,000 - 168,000 - 300,000 = 204,000 yen
                ',
                'choices' => [
                    'a' => '200,000',
                    'b' => '204,000',
                    'c' => '260,000',
                    'd' => '320,000'
                ]
