$solutions = [
    'APRIL-2025' => [
        1 => [
            'explanation' => 'This is an AND gate logic problem. The box in Figure 1 is an AND gate (outputs "Agree" only when both inputs are "Agree"). In Figure 2, Box1 receives Input1 and Input2, Box2 receives the output of Box1 and Input3. Therefore, Box2 will output "Agree" only when Box1 outputs "Agree" AND Input3 is "Agree". Box1 outputs "Agree" only when Input1 AND Input2 are both "Agree". Therefore, all three inputs must be "Agree" for the final output to be "Agree".',
            'steps' => [
                'Step 1: Identify the logic gate from Figure 1 - It\'s an AND gate (outputs 1 only when both inputs are 1)',
                'Step 2: Trace the signal flow: Input1 + Input2 → Box1 → Output1 → Box2',
                'Step 3: Box2 receives Output1 and Input3 → Final Output',
                'Step 4: Create truth table:',
                '   - If any input is "Disagree", the path is broken',
                '   - Only when all three are "Agree" does the final output become "Agree"',
                'Step 5: Therefore, the correct answer is d'
            ],
            'key_concepts' => ['Logic Gates', 'AND Gate', 'Boolean Algebra', 'Combinational Logic'],
            'difficulty' => 'Easy'
        ],
        2 => [
            'explanation' => 'Binary multiplication follows the same principles as decimal multiplication. 1011 (binary) = 11 (decimal), 101 (binary) = 5 (decimal). 11 × 5 = 55 (decimal) = 110111 (binary).',
            'steps' => [
                'Step 1: Write the multiplication vertically:',
                '   1011',
                '×   101',
                '--------',
                'Step 2: Multiply 1011 by the rightmost digit (1): 1011 × 1 = 1011',
                'Step 3: Multiply 1011 by the middle digit (0): 1011 × 0 = 0000 (shifted left one position)',
                'Step 4: Multiply 1011 by the leftmost digit (1): 1011 × 1 = 1011 (shifted left two positions)',
                'Step 5: Add all partial products:',
                '     1011',
                '    0000',
                '+ 1011',
                '--------',
                '  110111',
                'Step 6: The result is 110111'
            ],
            'key_concepts' => ['Binary Arithmetic', 'Binary Multiplication', 'Number Systems'],
            'difficulty' => 'Easy'
        ],
        3 => [
            'explanation' => 'Recall rate (also called sensitivity) is the ratio of true positives to actual positives. From the table: Quality controller identified 10 defective products (5+5). Machine learning model correctly identified 5 of these as defective. Recall = 5/10 = 0.5 or 50%.',
            'steps' => [
                'Step 1: Identify the recall rate definition: Recall = True Positives / (True Positives + False Negatives)',
                'Step 2: From the table:',
                '   - True Positives (ML said Defective, QC said Defective) = 5',
                '   - False Negatives (ML said Not Defective, QC said Defective) = 5',
                'Step 3: Calculate: Recall = 5 / (5 + 5) = 5/10 = 0.5',
                'Step 4: Therefore, the recall rate is 0.50 or 50%'
            ],
            'key_concepts' => ['Machine Learning', 'Recall Rate', 'Sensitivity', 'Confusion Matrix'],
            'difficulty' => 'Medium'
        ],
        4 => [
            'explanation' => 'For a fair six-sided die, probability of not getting a 1 on a single throw is 5/6. Since throws are independent, multiply probabilities for three throws: (5/6)³ = 125/216.',
            'steps' => [
                'Step 1: Probability of not getting 1 in one throw = 5/6 (favorable outcomes 2-6 out of 6)',
                'Step 2: For three independent throws, multiply probabilities: (5/6) × (5/6) × (5/6)',
                'Step 3: Calculate: (5 × 5 × 5) / (6 × 6 × 6) = 125/216',
                'Step 4: The answer is 125/216'
            ],
            'key_concepts' => ['Probability', 'Independent Events', 'Multiplication Rule'],
            'difficulty' => 'Easy'
        ],
        5 => [
            'explanation' => 'Source code refers to human-readable instructions written in a programming language. It must be compiled or interpreted to become machine-executable code.',
            'steps' => [
                'Step 1: Understand the definition - human-readable programming language instructions',
