            ],
            'key_concepts' => ['Storage Devices', 'SSD', 'IoT Hardware', 'Flash Memory'],
            'difficulty' => 'Very Easy'
        ],
        13 => [
            'explanation' => '64-bit CPUs can process 64 bits of data at once, while 32-bit CPUs process 32 bits. This allows 64-bit CPUs to handle larger numbers and address more memory in a single operation.',
            'steps' => [
                'Step 1: Compare 32-bit vs 64-bit CPUs:',
                '   - Word size: amount of data processed in one instruction',
                '   - 32-bit: processes 32 bits at once',
                '   - 64-bit: processes 64 bits at once (double)',
                'Step 2: Eliminate wrong options:',
                '   - b: Smaller cache reduces speed (false)',
                '   - c: Lower clock frequency reduces speed (false)',
