            ],
            'key_concepts' => ['System Architecture', 'Fault Tolerance', 'Redundancy', 'Dual Systems'],
            'difficulty' => 'Medium'
        ],
        15 => [
            'explanation' => 'Response time in client/server systems is affected by network speed (A) and server processing speed (D). Client-side factors (B,C) affect user experience but not system response time.',
            'steps' => [
                'Step 1: Define response time: Time from request submission to response receipt',
