        67 => [
            'explanation' => 'Profit = Sales Revenue - Cost = (r×s) - (p×q). Plan: (1500×1000) - (1000×1000) = 1,500,000 - 1,000,000 = 500,000. Result: (1350×1100) - (1000×1100) = 1,485,000 - 1,100,000 = 385,000. Ratio = 385,000/500,000 = 0.77 = 77%.',
            'steps' => [
                'Step 1: Calculate planned profit:',
                '   Sales revenue plan = r × s = 1500 × 1000 = 1,500,000',
                '   Cost plan = p × q = 1000 × 1000 = 1,000,000',
                '   Profit plan = 1,500,000 - 1,000,000 = 500,000',
                'Step 2: Calculate actual profit:',
                '   Sales revenue actual = 1350 × 1100 = 1,485,000',
                '   Cost actual = 1000 × 1100 = 1,100,000',
                '   Profit actual = 1,485,000 - 1,100,000 = 385,000',
                'Step 3: Calculate ratio: 385,000 / 500,000 = 0.77',
                'Step 4: Convert to percentage: 77%',
                'Step 5: Option a is correct'
            ],
            'key_concepts' => ['Financial Analysis', 'Profit Calculation', 'Business Metrics'],
            'difficulty' => 'Medium'
        ],
