        67 => [
            'explanation' => 'To minimize total time, schedule activities with shorter Y times later to reduce waiting. Sequence C→A→B minimizes idle time on machine Y.',
            'steps' => [
                'Step 1: Understand the problem: two-machine flow shop scheduling',
                'Step 2: Johnson\'s rule: schedule activities with smaller X time early, smaller Y time late',
                'Step 3: Compare sequences:',
                '   - A→B→C: X: 8+10+6=24, Y: 10+5+8=23, total ~33',
                '   - A→C→B: X: 8+6+10=24, Y: 10+8+5=23, total ~32',
                '   - C→A→B: X: 6+8+10=24, Y: 8+10+5=23, total ~31',
                '   - C→B→A: X: 6+10+8=24, Y: 8+5+10=23, total ~32',
                'Step 4: C→A→B gives minimum total time',
                'Step 5: Option c is correct'
            ],
            'key_concepts' => ['Scheduling', 'Flow Shop', 'Johnson\'s Rule'],
            'difficulty' => 'Hard'
        ],
        68 => [
            'explanation' => 'Calculate: 1 lunch box = 5 dumplings. 1 dumpling = 20g stuffing. 100g stuffing = 60g meat. So per lunch box: 5 × 20 = 100g stuffing × (60/100) = 60g meat. For 100 boxes: 100 × 60 = 6,000g.',
            'steps' => [
                'Step 1: Determine dumplings per lunch box: 5 units',
                'Step 2: Stuffing per dumpling: 20g',
                'Step 3: Stuffing per lunch box: 5 × 20 = 100g',
                'Step 4: Meat per 100g stuffing: 60g',
                'Step 5: Meat per lunch box: 100 × (60/100) = 60g',
                'Step 6: For 100 lunch boxes: 100 × 60 = 6,000g',
                'Step 7: Option c is correct'
            ],
            'key_concepts' => ['Bill of Materials', 'Recipe Calculation', 'Production Planning'],
            'difficulty' => 'Medium'
        ],
