    'APRIL-2023' => [
        1 => [
            'explanation' => 'Variance measures how spread out data is. Histogram D with two peaks at extremes (bimodal) has the largest spread between values, hence the largest variance.',
            'steps' => [
                'Step 1: Understand variance - measures how far data points are from the mean',
                'Step 2: Histogram A: Narrow peak - low variance (data clustered)',
                'Step 3: Histogram B: Medium spread - moderate variance',
                'Step 4: Histogram C: Wide flat - medium-high variance',
                'Step 5: Histogram D: Bimodal with peaks at extremes - largest spread (highest variance)',
                'Step 6: Therefore, option d is correct'
            ],
            'key_concepts' => ['Statistics', 'Variance', 'Histograms', 'Data Distribution'],
            'difficulty' => 'Easy'
        ],
        2 => [
            'explanation' => 'In computing, 1 Tbyte = 10^12 bytes (terabyte, not 2^40 which is tebibyte). Hard disk manufacturers use decimal prefixes.',
            'steps' => [
                'Step 1: Understand storage units:',
                '   - 1 TB (Terabyte) = 10^12 bytes (manufacturer definition)',
                '   - 1 TiB (Tebibyte) = 2^40 bytes (binary definition)',
                'Step 2: Evaluate options:',
                '   - a: 2 × 10^12 bytes (correct for 2 TB) ✓',
                '   - b: dpi is dots per inch, not cm² ✗',
                '   - c: 3.3 GHz = 3.3 × 10^9 Hz, not 2^20 ✗',
                '   - d: 56 kbps = 56 × 10^3 bits/sec, not 2^10 ✗',
                'Step 3: Option a is correct'
            ],
            'key_concepts' => ['Units of Measurement', 'Storage Capacity', 'Data Transfer Rates'],
            'difficulty' => 'Easy'
        ],
        3 => [
            'explanation' => '$20,000 is NOT less than $10,000 → N. 3 days reduction IS less than 1 week (5 days) → Y. This matches Case 3: N,Y → Reward = $150.',
            'steps' => [
                'Step 1: Determine first condition: Improvement less than $10,000?',
                '   - $20,000 ≥ $10,000 → No (N)',
                'Step 2: Determine second condition: Turnaround time reduction less than 1 week?',
                '   - 3 days < 5 days → Yes (Y)',
                'Step 3: Match to decision table:',
                '   - Case 1: Y,Y → $50',
                '   - Case 2: Y,N → $100',
                '   - Case 3: N,Y → $150',
                '   - Case 4: N,N → $300',
                'Step 4: N,Y matches Case 3 → Reward = $150',
                'Step 5: Option c is correct'
            ],
            'key_concepts' => ['Decision Tables', 'Business Rules', 'Logic Analysis'],
            'difficulty' => 'Easy'
        ],
        4 => [
            'explanation' => 'Mean = sum of all values / number of values = (10+20+20+20+40+50+100+440+2000) / 9 = 2700 / 9 = 300. Median = middle value when sorted = 40 (5th of 9 numbers).',
            'steps' => [
                'Step 1: Sort data: 10, 20, 20, 20, 40, 50, 100, 440, 2000',
                'Step 2: Calculate mean:',
                '   Sum = 10+20+20+20+40+50+100+440+2000 = 2700',
                '   Number of values = 9',
                '   Mean = 2700 ÷ 9 = 300',
                'Step 3: Find median:',
                '   With 9 numbers, median is 5th value',
                '   5th value = 40',
                'Step 4: Mean = 300, Median = 40',
                'Step 5: Option d is correct'
            ],
            'key_concepts' => ['Statistics', 'Mean', 'Median', 'Central Tendency'],
            'difficulty' => 'Easy'
        ],
