        57 => [
            'explanation' => '40% complete at 5 months means 60% remaining. 6M cost for 40% → cost per % = 150,000. Remaining 60% = 9M. Total = 15M, budget 10M, excess 5M.',
            'steps' => [
                'Step 1: Budget = 10M for 10 months = 1M/month',
                'Step 2: At 5 months: actual cost 6M, 40% complete',
                'Step 3: Cost per percentage = 6M / 40 = 150,000 per %',
                'Step 4: Remaining 60% will cost: 60 × 150,000 = 9M',
                'Step 5: Total actual = 6M + 9M = 15M',
                'Step 6: Budget excess = 15M - 10M = 5M',
                'Step 7: Option d is correct'
            ],
            'key_concepts' => ['Project Cost Management', 'Earned Value', 'Budget Control'],
            'difficulty' => 'Hard'
        ],
