        72 => [
            'explanation' => 'Profit plan = (1,500×1,000) - (1,000×1,000) = 500,000. Profit result = (1,350×1,100) - (1,000×1,100) = 385,000. Ratio = 385,000/500,000 = 77%.',
            'steps' => [
                'Step 1: Calculate profit plan:',
                '   Revenue = 1,500 × 1,000 = 1,500,000',
                '   Cost = 1,000 × 1,000 = 1,000,000',
                '   Profit = 1,500,000 - 1,000,000 = 500,000',
                'Step 2: Calculate profit result:',
                '   Revenue = 1,350 × 1,100 = 1,485,000',
                '   Cost = 1,000 × 1,100 = 1,100,000',
                '   Profit = 1,485,000 - 1,100,000 = 385,000',
                'Step 3: Ratio = 385,000 / 500,000 = 0.77 = 77%',
                'Step 4: Option a is correct'
            ],
            'key_concepts' => ['Financial Analysis', 'Profit Calculation', 'Business Metrics'],
            'difficulty' => 'Medium'
        ],
