'APRIL-2022' => [
    1 => [
        'explanation' => 'To search for Japanese restaurants in both Sapporo and Hakodate, we need restaurants in Sapporo OR Hakodate, AND they must be Japanese restaurants. This translates to ("Sapporo" OR "Hakodate") AND "Japanese restaurant".',
        'steps' => [
            'Step 1: Identify requirement: Japanese restaurants in Sapporo AND Japanese restaurants in Hakodate',
            'Step 2: This means: (restaurants in Sapporo) OR (restaurants in Hakodate)',
            'Step 3: AND they must be Japanese restaurants',
            'Step 4: Logical expression: ("Sapporo" OR "Hakodate") AND "Japanese restaurant"',
            'Step 5: Option c is correct'
        ],
        'key_concepts' => ['Boolean Logic', 'Search Operators', 'AND/OR Operations'],
        'difficulty' => 'Easy'
    ],
    2 => [
        'explanation' => 'The intersection (A ∩ B) contains elements that are in both A and B. The union (A ∪ B) contains all elements in A or B. Any element in the intersection is automatically in the union, so (A ∩ B) ⊆ (A ∪ B) is always true.',
        'steps' => [
            'Step 1: Understand set relationships:',
            '   - A ∩ B = elements in both A and B',
            '   - A ∪ B = elements in A or B (or both)',
            'Step 2: Any element in A ∩ B is also in A (and in B)',
            'Step 3: Therefore, it must be in A ∪ B',
            'Step 4: So (A ∩ B) is always a subset of (A ∪ B)',
            'Step 5: Option c is correct'
        ],
        'key_concepts' => ['Set Theory', 'Intersection', 'Union', 'Subset'],
        'difficulty' => 'Easy'
    ],
    3 => [
        'explanation' => 'Binary multiplication: 1011 (binary) = 11 (decimal), 101 (binary) = 5 (decimal). 11 × 5 = 55 (decimal) = 110111 (binary).',
        'steps' => [
            'Step 1: Write multiplication vertically:',
            '   1011',
            '×  101',
            '--------',
            'Step 2: Multiply by rightmost digit (1): 1011 × 1 = 1011',
            'Step 3: Multiply by middle digit (0): 1011 × 0 = 0000 (shift left 1)',
            'Step 4: Multiply by leftmost digit (1): 1011 × 1 = 1011 (shift left 2)',
            'Step 5: Add: 1011 + 00000 + 101100 = 110111',
            'Step 6: Option d is correct'
        ],
        'key_concepts' => ['Binary Arithmetic', 'Binary Multiplication', 'Number Systems'],
        'difficulty' => 'Easy'
    ],
    4 => [
        'explanation' => 'With 5 candidates and dual roles allowed, chairperson can be any of 5, secretary can be any of 5 (including same person). Total = 5 × 5 = 25 combinations.',
        'steps' => [
            'Step 1: Number of choices for chairperson = 5',
            'Step 2: Number of choices for secretary = 5 (can be same as chairperson)',
            'Step 3: Total combinations = 5 × 5 = 25',
            'Step 4: Option d is correct'
        ],
        'key_concepts' => ['Combinatorics', 'Counting Principle', 'Permutations'],
        'difficulty' => 'Very Easy'
    ],
    5 => [
        'explanation' => 'Queue follows FIFO (First-In-First-Out). Order: enqueue 33,27,12 → [33,27,12]. Enqueue 45 → [33,27,12,45]. Dequeue first: remove 33 → [27,12,45]. Dequeue second: remove 27 → [12,45]. Second retrieved is 27.',
        'steps' => [
            'Step 1: Initial queue (front to back): [33, 27, 12]',
            'Step 2: Enqueue 45: [33, 27, 12, 45]',
            'Step 3: First dequeue: remove 33 → [27, 12, 45]',
            'Step 4: Second dequeue: remove 27 → [12, 45]',
            'Step 5: Second element retrieved = 27',
            'Step 6: Option b is correct'
        ],
        'key_concepts' => ['Queue', 'FIFO', 'Data Structures'],
        'difficulty' => 'Very Easy'
    ],
    6 => [
        'explanation' => 'HTML (Hypertext Markup Language) uses tags to specify the logical structure and layout of web pages, defining headings, paragraphs, links, etc.',
        'steps' => [
