    ],
    9 => [
        'explanation' => 'First box: 49 ÷ 11 = 4 remainder 5 → B1=11, B2=5. Second box: A1=11, A2=5 → 11 ÷ 5 = 2 remainder 1 → B2=1.',
        'steps' => [
            'Step 1: First box calculation:',
            '   A1=49, A2=11',
            '   B1 = A2 = 11',
            '   B2 = remainder of 49 ÷ 11 = 5',
            'Step 2: Second box receives:',
            '   A1 = B1 from first box = 11',
            '   A2 = B2 from first box = 5',
            'Step 3: Second box B2 = remainder of 11 ÷ 5 = 1',
            'Step 4: Option a is correct'
