    15 => [
        'explanation' => 'Fault tolerance measures: mirroring (RAID 1) provides data redundancy; UPS ensures power continuity during outages. Minimizing maintenance (2) and line grouping (3) don\'t provide fault tolerance.',
        'steps' => [
            'Step 1: Identify measures for normal execution despite failure',
            'Step 2: Evaluate each:',
            '   (1) Mirroring - redundant data ✓',
            '   (2) Minimize maintenance - actually increases risk ✗',
            '   (3) Line grouping - not fault tolerance ✗',
            '   (4) UPS - power redundancy ✓',
            'Step 3: Appropriate: (1) and (4)',
            'Step 4: Option b is correct'
        ],
        'key_concepts' => ['Fault Tolerance', 'Redundancy', 'High Availability'],
        'difficulty' => 'Medium'
    ],
    16 => [
