        'steps' => [
            'Step 1: Time per file = 3 MB ÷ 10 MB/s = 0.3 seconds',
            'Step 2: Monday-Thursday: 1,000 files × 0.3 sec = 300 sec = 5 minutes',
            'Step 3: 4 days × 5 min = 20 minutes',
            'Step 4: Friday: 6,000 files × 0.3 sec = 1,800 sec = 30 minutes',
