    97 => [
        'explanation' => 'Weighted scores: Vendor A = 2×2 + 3×3 + 5×4 = 4+9+20=33; B=8+12+10=30; C=6+6+20=32; D=6+9+15=30. Vendor A has highest total.',
        'steps' => [
            'Step 1: Calculate weighted scores:',
            '   Vendor A: (2×2) + (3×3) + (5×4) = 4 + 9 + 20 = 33',
            '   Vendor B: (2×4) + (3×4) + (5×2) = 8 + 12 + 10 = 30',
            '   Vendor C: (2×3) + (3×2) + (5×4) = 6 + 6 + 20 = 32',
            '   Vendor D: (2×3) + (3×3) + (5×3) = 6 + 9 + 15 = 30',
            'Step 2: Highest score = 33 (Vendor A)',
            'Step 3: Option a is correct'
        ],
        'key_concepts' => ['Vendor Selection', 'Weighted Scoring', 'Decision Making'],
        'difficulty' => 'Easy'
    ],
