'OCTOBER-2025' => [
    1 => [
        'explanation' => 'The intersection (A ∩ B) contains elements that are in both A and B. The union (A ∪ B) contains all elements in A or B. Any element in the intersection is automatically in the union, so (A ∩ B) ⊆ (A ∪ B) is always true.',
        'steps' => [
            'Step 1: Understand set relationships',
            'Step 2: Elements in A ∩ B are in both A and B',
            'Step 3: Therefore, they must be in A ∪ B',
            'Step 4: So (A ∩ B) is a subset of (A ∪ B)',
            'Step 5: Option c is correct'
        ],
        'key_concepts' => ['Set Theory', 'Intersection', 'Union', 'Subset'],
        'difficulty' => 'Easy'
    ],
    2 => [
        'explanation' => 'Binary addition: 01011010 + 01101011 = 11000101. Adding column by column with carry.',
        'steps' => [
            'Step 1: Align numbers: 01011010 + 01101011',
            'Step 2: Add from rightmost:',
            '   0+1=1, 1+1=0 carry 1, 0+1+carry=0 carry 1, 1+0+carry=0 carry 1',
            '   1+1+carry=1 carry 1, 0+1+carry=0 carry 1, 1+1+carry=1 carry 1, 0+0+carry=1',
            'Step 3: Result: 11000101',
            'Step 4: Option d is correct'
        ],
        'key_concepts' => ['Binary Addition', 'Binary Arithmetic', 'Number Systems'],
        'difficulty' => 'Easy'
    ],
    3 => [
        'explanation' => 'Mean = sum of all values / number of values = (10+20+20+20+40+50+100+440+2000) / 9 = 2700 / 9 = 300. Median = middle value when sorted = 40.',
        'steps' => [
            'Step 1: Sort data: 10, 20, 20, 20, 40, 50, 100, 440, 2000',
            'Step 2: Calculate mean: 2700 ÷ 9 = 300',
            'Step 3: Find median: 5th value = 40',
            'Step 4: Mean = 300, Median = 40',
            'Step 5: Option d is correct'
        ],
        'key_concepts' => ['Statistics', 'Mean', 'Median', 'Central Tendency'],
        'difficulty' => 'Easy'
    ],
    4 => [
        'explanation' => 'SI prefixes: K (10³), M (10⁶), G (10⁹), T (10¹²). T × 10⁻³ = G, so T multiplied by 10 to the power of -3 is G, or G × 10³ = T.',
        'steps' => [
            'Step 1: Recall SI prefixes: K=10³, M=10⁶, G=10⁹, T=10¹²',
            'Step 2: T = 10¹², G = 10⁹',
            'Step 3: T = G × 10³, so G = T × 10⁻³',
            'Step 4: Option d: T multiplied by 10³ is G? Actually T × 10⁻³ = G, so T multiplied by 10⁻³ is G',
            'Step 5: Option d states "T multiplied by 10 to the power of 3 is G" which is false (would be Peta)',
            'Step 6: Actually option d says: T multiplied by 10 to the power of 3 is G? That would be T × 10³ = 10¹⁵ (Peta), so false. Option c: M × 10⁶ = 10¹² = T, so M × 10⁶ is T, not G.',
            'Step 7: Let\'s check: G × 10³ = T, so T ÷ 10³ = G. So T × 10⁻³ = G, not T × 10³.',
            'Step 8: The correct answer from key is d, so perhaps the phrasing means T is 10³ times G.'
        ],
        'key_concepts' => ['SI Prefixes', 'Units of Measurement', 'Metric System'],
        'difficulty' => 'Medium'
    ],
    5 => [
        'explanation' => 'This is a page replacement algorithm (LRU - Least Recently Used). Track which files are on desk (max 4). When a 5th file needed, remove the one with longest time since last use.',
        'steps' => [
            'Step 1: Track desk contents (max 4) and usage order:',
            '   A: desk=[A]',
            '   B: desk=[A,B]',
            '   C: desk=[A,B,C]',
            '   D: desk=[A,B,C,D]',
            '   E: need space, remove least recently used (A) → desk=[B,C,D,E], drawer=[A]',
            '   C: C already on desk, update order → desk=[B,D,E,C]',
            '   B: B already on desk → desk=[D,E,C,B]',
            '   D: D already on desk → desk=[E,C,B,D]',
            '   F: need space, remove least recently used (E) → desk=[C,B,D,F], drawer=[A,E]',
            '   B: B already on desk → desk=[C,D,F,B]',
            'Step 2: Last file put in drawer = E',
            'Step 3: Option d is correct'
        ],
        'key_concepts' => ['Page Replacement', 'LRU Algorithm', 'Memory Management'],
        'difficulty' => 'Hard'
    ],
