    51 => [
        'explanation' => 'Work = Members × Days × Productivity. Let productivity of initial members = 1, new members = 0.5. Work = 6 × 20 × 1 = 120 units. With x new members: (6 + 0.5x) × 15 = 120 → 90 + 7.5x = 120 → 7.5x = 30 → x = 4.',
        'steps' => [
            'Step 1: Calculate total work units: 6 members × 20 days = 120 member-days',
            'Step 2: New productivity: initial members = 1, new members = 0.5',
            'Step 3: Let n = number of new members',
            'Step 4: (6 + 0.5n) × 15 = 120',
            'Step 5: 90 + 7.5n = 120',
            'Step 6: 7.5n = 30, n = 4',
            'Step 7: Option c is correct'
        ],
        'key_concepts' => ['Project Management', 'Resource Planning', 'Productivity'],
        'difficulty' => 'Medium'
    ],
