    68 => [
        'explanation' => 'Current: unit price=1,000, variable cost=200. New: price=800, quantity=840. Profit = 840×800 - 840×200 - 300,000 = 672,000 - 168,000 - 300,000 = 204,000.',
        'steps' => [
            'Step 1: Calculate current unit price: 700,000 / 700 = 1,000 yen',
            'Step 2: Calculate variable cost per unit: 140,000 / 700 = 200 yen',
            'Step 3: New price = 1,000 × 0.8 = 800 yen',
            'Step 4: New quantity = 700 × 1.2 = 840 units',
            'Step 5: New sales = 840 × 800 = 672,000 yen',
            'Step 6: New variable cost = 840 × 200 = 168,000 yen',
            'Step 7: Fixed cost = 300,000 yen',
            'Step 8: Operating profit = 672,000 - 168,000 - 300,000 = 204,000 yen',
            'Step 9: Option b is correct'
        ],
        'key_concepts' => ['Profit Analysis', 'Cost-Volume-Profit', 'Operating Profit'],
        'difficulty' => 'Medium'
    ],
