'OCTOBER-2023' => [
    1 => [
        'explanation' => 'Probability without replacement: P(B,B,B) = (4/7)×(3/6)×(2/5)=24/210=0.114. P(B,B,W)= (4/7)×(3/6)×(3/5)=36/210=0.171. P(B,W,B)= (4/7)×(3/6)×(3/5)=36/210. P(W,B,B)= (3/7)×(4/6)×(3/5)=36/210. B,B,B has lowest probability.',
        'steps' => [
            'Step 1: Total balls: 3 white, 4 black = 7 total',
            'Step 2: Calculate P(black, black, black): 4/7 × 3/6 × 2/5 = 24/210',
            'Step 3: Calculate P(black, black, white): 4/7 × 3/6 × 3/5 = 36/210',
            'Step 4: Calculate P(black, white, black): 4/7 × 3/6 × 3/5 = 36/210',
            'Step 5: Calculate P(white, black, black): 3/7 × 4/6 × 3/5 = 36/210',
            'Step 6: Lowest is 24/210 = option a',
            'Step 7: Option a is correct'
        ],
        'key_concepts' => ['Probability', 'Without Replacement', 'Combinatorics'],
        'difficulty' => 'Medium'
    ],
    2 => [
