// Add this to the solutions array after the OCTOBER-2023 solutions

'OCTOBER-2022' => [
    1 => [
        'explanation' => 'Position values: 16,8,4,2,1. ■■■□□ = 16+8+4+0+0 = 28, but 28 not in options. ■■□□□ = 16+8=24. The question likely shows ■■□□□ pattern for 24.',
        'steps' => [
            'Step 1: Identify position values: leftmost=16, then 8,4,2,1',
            'Step 2: ■ (black) = value, □ (white) = 0',
            'Step 3: Pattern ■■□□□ = positions 1 and 2 black = 16+8=24',
            'Step 4: Option c is correct'
        ],
        'key_concepts' => ['Binary Representation', 'Positional Notation', 'Number Systems'],
        'difficulty' => 'Easy'
    ],
    2 => [
        'explanation' => 'Total patterns for 5 lamps = 2^5 = 32. Subtract patterns with 0 lamps (1) and 1 lamp (5). 32 - 1 - 5 = 26 patterns with 2 or more lamps.',
        'steps' => [
            'Step 1: Total possible patterns = 2^5 = 32',
            'Step 2: Pattern with 0 lamps = 1',
            'Step 3: Patterns with exactly 1 lamp = 5 (any of 5 lamps on)',
            'Step 4: Patterns with 2+ lamps = 32 - 1 - 5 = 26',
            'Step 5: Option c is correct'
        ],
        'key_concepts' => ['Combinatorics', 'Binary Combinations', 'Counting'],
        'difficulty' => 'Easy'
    ],
    3 => [
        'explanation' => 'Binary addition: 01011010 + 01101011 = 11000101. Adding column by column with carry.',
        'steps' => [
            'Step 1: Align: 01011010 + 01101011',
            'Step 2: Add from right: 0+1=1, 1+1=0 carry1, 0+1+carry=0 carry1, 1+0+carry=0 carry1, 1+1+carry=1 carry1, 0+1+carry=0 carry1, 1+1+carry=1 carry1, 0+0+carry=1',
            'Step 3: Result: 11000101',
            'Step 4: Option d is correct'
        ],
        'key_concepts' => ['Binary Addition', 'Binary Arithmetic', 'Number Systems'],
        'difficulty' => 'Easy'
    ],
    4 => [
        'explanation' => 'Analog uses continuous physical quantities; digital uses discrete numerical values. CDs store digital data.',
        'steps' => [
            'Step 1: A = analog (continuous)',
            'Step 2: B = digital (discrete)',
            'Step 3: C = digital (CDs store digital)',
            'Step 4: Option b matches: analog, digital, digital',
            'Step 5: Option b is correct'
        ],
        'key_concepts' => ['Analog vs Digital', 'Data Representation', 'CD Technology'],
        'difficulty' => 'Very Easy'
    ],
    5 => [
        'explanation' => 'x=2,y=3. Loop: y=2,x=4; y=1,x=5; exit. Final x=5.',
        'steps' => [
            'Step 1: Initialize x=2, y=3',
            'Step 2: First iteration: y=3-1=2, x=2+2=4, y≠1 continue',
            'Step 3: Second iteration: y=2-1=1, x=4+1=5, y=1 exit',
            'Step 4: Final x=5',
            'Step 5: Option b is correct'
        ],
        'key_concepts' => ['Programming Logic', 'Loops', 'Algorithm Tracing'],
        'difficulty' => 'Medium'
    ],
    6 => [
        'explanation' => 'XML uses tags enclosed in angle brackets (< >) to describe logical structure.',
        'steps' => [
