'OCTOBER-2022' => [
    1 => [
        'explanation' => 'Position values: 16,8,4,2,1. ■■■□□ = 16+8+4+0+0 = 28, but 28 not in options. The pattern shown likely represents 24 (16+8) which is ■■□□□.',
        'steps' => [
            'Step 1: Position values: leftmost=16, then 8,4,2,1',
            'Step 2: ■ (black) = value, □ (white) = 0',
            'Step 3: Pattern for 24 = 16+8 = ■■□□□',
            'Step 4: Option c is correct'
        ],
        'key_concepts' => ['Binary Representation', 'Positional Notation', 'Number Systems'],
        'difficulty' => 'Easy'
    ],
    2 => [
        'explanation' => 'Total patterns = 2^5 = 32. Subtract patterns with 0 lamps (1) and 1 lamp (5). 32 - 1 - 5 = 26.',
        'steps' => [
            'Step 1: Total patterns = 2^5 = 32',
            'Step 2: 0 lamps on = 1 pattern',
            'Step 3: 1 lamp on = 5 patterns (any of 5 lamps)',
            'Step 4: Patterns with 2+ lamps = 32 - 1 - 5 = 26',
            'Step 5: Option c is correct'
        ],
        'key_concepts' => ['Combinatorics', 'Binary Combinations', 'Counting'],
        'difficulty' => 'Easy'
    ],
    3 => [
        'explanation' => 'Binary addition: 01011010 + 01101011 = 11000101.',
        'steps' => [
            'Step 1: Align: 01011010 + 01101011',
            'Step 2: Add from right: 0+1=1, 1+1=0 carry1, 0+1+carry=0 carry1, 1+0+carry=0 carry1, 1+1+carry=1 carry1, 0+1+carry=0 carry1, 1+1+carry=1 carry1, 0+0+carry=1',
            'Step 3: Result: 11000101',
            'Step 4: Option d is correct'
        ],
        'key_concepts' => ['Binary Addition', 'Binary Arithmetic'],
        'difficulty' => 'Easy'
    ],
