$allQuestions = [];
$allQuestionsList = [];

foreach ($exams as $year => $exam) {
    foreach ($exam['questions'] as $qNum => $question) {
        $allQuestionsList[] = [
            'year' => $year,
            'qNum' => $qNum,
            'title' => $exam['title'],
            'answer_key' => $exam['answer_key'][$qNum],
            'text' => $question['text'],
            'choices' => $question['choices'],
            'image' => $question['image'] ?? null
        ];
    }
}

function shuffleQuestions($questions, $count = 100) {
    $shuffled = $questions;
    shuffle($shuffled);
    return array_slice($shuffled, 0, $count);
}

session_start();
if (!isset($_SESSION['exam_sessions'])) {
    $_SESSION['exam_sessions'] = [];
}
if (!isset($_SESSION['random_exams'])) {
    $_SESSION['random_exams'] = [];
}

$theme = 'light';
if (isset($_COOKIE['theme_preference'])) {
    $theme = $_COOKIE['theme_preference'];
} elseif (isset($_SESSION['theme_preference'])) {
    $theme = $_SESSION['theme_preference'];
}
if (isset($_GET['toggle_theme'])) {
    $newTheme = ($theme === 'light') ? 'dark' : 'light';
    setcookie('theme_preference', $newTheme, time() + 365 * 24 * 3600, '/');
    $_SESSION['theme_preference'] = $newTheme;
    header("Location: " . strtok($_SERVER['REQUEST_URI'], '?'));
    exit;
}

function getAnswerLetter($key) {
    $map = ['a' => 'A', 'b' => 'B', 'c' => 'C', 'd' => 'D'];
    return isset($map[$key]) ? $map[$key] : '?';
}

function getQuestionCategory($questionText) {
    $textLower = strtolower($questionText);
    $techKeywords = ['binary', 'cpu', 'memory', 'cache', 'gpu', 'network', 'ip', 'dns', 'database', 'sql', 'encryption', 'algorithm', 'programming', 'software', 'hardware', 'interface', 'iot', 'ai', 'machine learning', 'deep learning', 'cad', 'api', 'vr', 'ar', 'biometric', 'firewall', 'wireless', 'bluetooth', 'nfc', 'rfid', 'sensor', 'actuator', 'embedded', 'firmware', 'driver', 'os', 'operating system', 'linux', 'windows', 'android', 'ios', 'multitasking', 'thread', 'process', 'ram', 'rom', 'storage', 'hdd', 'ssd', 'graphics', 'display', 'printer', 'scanner', 'resolution', 'pixel', 'compression', 'mpeg', 'jpeg', 'html', 'xml', 'css', 'javascript', 'java', 'python', 'compiler', 'interpreter', 'debug', 'data structure', 'stack', 'queue', 'array', 'virtualization', 'cloud computing', 'edge computing', '5g', 'lte', 'lpwa', 'wifi', 'ethernet', 'router', 'switch', 'hub', 'gateway', 'bit', 'byte', 'digital', 'analog', 'signal', 'frequency', 'clock'];
    
    $mgmtKeywords = ['project', 'management', 'wbs', 'pert', 'schedule', 'cost', 'quality', 'risk', 'stakeholder', 'change management', 'service desk', 'sla', 'itil', 'governance', 'audit', 'compliance', 'internal control', 'pdca', 'isms', 'project manager', 'scope', 'milestone', 'deliverable', 'resource', 'budget', 'timeline', 'deadline', 'critical path', 'gantt', 'estimation', 'function point', 'maintenance', 'testing', 'unit test', 'integration test', 'system test', 'acceptance test', 'uat', 'black box', 'white box', 'regression', 'waterfall', 'agile', 'devops', 'service level', 'incident', 'problem', 'release', 'configuration', 'facility', 'data center', 'backup', 'disaster recovery', 'business continuity', 'bcp', 'itsm', 'help desk', 'escalation', 'workaround', 'root cause'];
    
    $stratKeywords = ['strategy', 'business', 'marketing', '3c', 'swot', 'balanced scorecard', 'portfolio', 'm&a', 'joint venture', 'outsourcing', 'bpr', 'scm', 'crm', 'erp', 'knowledge management', 'value chain', 'benchmarking', 'kpi', 'kgi', 'strategic', 'vision', 'mission', 'goal', 'objective', 'competitive', 'advantage', 'differentiation', 'cost leadership', 'niche', 'market', 'customer', 'supplier', 'partner', 'alliance', 'acquisition', 'merger', 'spin-off', 'franchise', 'license', 'patent', 'intellectual property', 'r&d', 'innovation', 'digital transformation', 'dx', 'fintech', 'hr tech', 'mot', 'technology management', 'roadmap', 'bcg matrix', 'product portfolio', 'core competence', 'value proposition', 'business model', 'supply chain', 'logistics', 'procurement', 'inventory', 'mrp', 'pos system', 'edi', 'b2b', 'b2c', 'c2c', 'b2e', 'crowdfunding', 'sharing economy', 'platform business', 'api economy', 'lean startup', 'mvp', 'company', 'organization', 'sales', 'profit', 'revenue'];
    
    foreach ($techKeywords as $kw) {
        if (strpos($textLower, $kw) !== false) return 'Technology';
    }
    foreach ($mgmtKeywords as $kw) {
        if (strpos($textLower, $kw) !== false) return 'Management';
    }
    foreach ($stratKeywords as $kw) {
        if (strpos($textLower, $kw) !== false) return 'Strategy';
    }
    
    return 'Technology';
}

$page = isset($_GET['page']) ? $_GET['page'] : 'home';
$year = isset($_GET['year']) ? $_GET['year'] : '';
$questionNum = isset($_GET['q']) ? (int)$_GET['q'] : 1;
$mode = isset($_GET['mode']) ? $_GET['mode'] : 'view';
$action = isset($_GET['action']) ? $_GET['action'] : '';

$totalExamSeconds = 7200;

// Random Exam Actions
if ($action === 'generate_random_exam') {
    $randomQuestions = shuffleQuestions($allQuestionsList, 100);
    $examId = 'RANDOM_' . date('Ymd_His');
    $reindexedQuestions = [];
    $answerKey = [];
    foreach ($randomQuestions as $index => $q) {
        $qNum = $index + 1;
        $reindexedQuestions[$qNum] = [
            'text' => $q['text'],
            'choices' => $q['choices'],
            'image' => $q['image'],
            'source_year' => $q['year'],
            'source_qNum' => $q['qNum']
        ];
        $answerKey[$qNum] = $q['answer_key'];
    }
    $_SESSION['random_exams'][$examId] = [
        'id' => $examId,
        'title' => 'Random Generated Exam',
        'questions' => $reindexedQuestions,
        'answer_key' => $answerKey,
        'created' => date('Y-m-d H:i:s')
    ];
    header("Location: ?page=exam&exam_type=random&exam_id=" . urlencode($examId) . "&mode=view");
    exit;
}

if ($action === 'start_random_exam' && isset($_GET['exam_id'])) {
    $examId = $_GET['exam_id'];
    if (isset($_SESSION['random_exams'][$examId])) {
        $_SESSION['exam_sessions'][$examId] = [
            'start_time' => time(),
            'answers' => [],
            'completed' => false,
            'submitted' => false,
            'question_start_times' => []
        ];
        $_SESSION['exam_sessions'][$examId]['question_start_times'][1] = time();
        header("Location: ?page=exam&exam_type=random&exam_id=" . urlencode($examId) . "&mode=practice&q=1");
        exit;
    }
}

if ($action === 'submit_random_exam' && isset($_GET['exam_id'])) {
    $examId = $_GET['exam_id'];
    if (isset($_SESSION['exam_sessions'][$examId])) {
        $_SESSION['exam_sessions'][$examId]['submitted'] = true;
        $_SESSION['exam_sessions'][$examId]['completed'] = true;
        header("Location: ?page=random_results&exam_id=" . urlencode($examId));
        exit;
    }
}

if (isset($_GET['reset_random_exam']) && isset($_GET['exam_id'])) {
    $examId = $_GET['exam_id'];
    unset($_SESSION['exam_sessions'][$examId]);
    header("Location: ?page=home");
    exit;
}

// Past Exam Actions
if ($action === 'start_past_exam' && $year && isset($exams[$year])) {
    $_SESSION['exam_sessions'][$year] = [
        'start_time' => time(),
        'answers' => [],
        'completed' => false,
        'submitted' => false,
        'question_start_times' => []
    ];
    $_SESSION['exam_sessions'][$year]['question_start_times'][1] = time();
    header("Location: ?page=past_exam&year=" . urlencode($year) . "&mode=practice&q=1");
    exit;
}

if ($action === 'submit_past_exam' && isset($_GET['year'])) {
    $year = $_GET['year'];
    if (isset($exams[$year]) && isset($_SESSION['exam_sessions'][$year])) {
        $_SESSION['exam_sessions'][$year]['submitted'] = true;
        $_SESSION['exam_sessions'][$year]['completed'] = true;
        header("Location: ?page=past_results&year=" . urlencode($year));
        exit;
    }
}

if (isset($_GET['reset_past_exam']) && isset($_GET['year'])) {
    $year = $_GET['year'];
    unset($_SESSION['exam_sessions'][$year]);
    header("Location: ?page=home");
    exit;
}

// Handle answer submission
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['save_answer'])) {
    $examId = $_POST['exam_id'] ?? '';
    $qNum = $_POST['qnum'] ?? '';
    $answer = $_POST['answer'] ?? '';
    $examType = $_POST['exam_type'] ?? '';
    
    if ($examType === 'random' && $examId && isset($_SESSION['exam_sessions'][$examId])) {
        $_SESSION['exam_sessions'][$examId]['answers'][$qNum] = $answer;
        $redirect = $_POST['redirect'] ?? "?page=exam&exam_type=random&exam_id=" . urlencode($examId) . "&mode=practice&q={$qNum}";
        header("Location: $redirect");
        exit;
    } elseif ($examType === 'past' && isset($_POST['year']) && isset($_SESSION['exam_sessions'][$_POST['year']])) {
        $_SESSION['exam_sessions'][$_POST['year']]['answers'][$qNum] = $answer;
        $redirect = $_POST['redirect'] ?? "?page=past_exam&year=" . urlencode($_POST['year']) . "&mode=practice&q={$qNum}";
        header("Location: $redirect");
        exit;
    }
    header("Location: ?page=home");
    exit;
}

// Time calculations for active exam
$timeRemaining = $totalExamSeconds;
$timeElapsed = 0;
$timePercentage = 0;
$examActive = false;
$activeExamId = null;
$activeExamType = null;
$timeOnQuestion = 0;
$questionTimeRemaining = 60;
$answeredCount = 0;
$showAlarm = false;

if (($page === 'past_exam' || ($page === 'exam' && isset($_GET['exam_type']) && $_GET['exam_type'] === 'random')) && $mode === 'practice') {
    if ($page === 'past_exam' && $year && isset($_SESSION['exam_sessions'][$year]) && !$_SESSION['exam_sessions'][$year]['submitted']) {
        $examActive = true;
        $activeExamId = $year;
        $activeExamType = 'past';
        $startTime = $_SESSION['exam_sessions'][$year]['start_time'];
        $timeElapsed = time() - $startTime;
        $timeRemaining = max(0, $totalExamSeconds - $timeElapsed);
        $answeredCount = count($_SESSION['exam_sessions'][$year]['answers'] ?? []);
        if ($timeRemaining <= 0 && !$_SESSION['exam_sessions'][$year]['submitted']) {
            $_SESSION['exam_sessions'][$year]['submitted'] = true;
            header("Location: ?page=past_results&year=" . urlencode($year) . "&timeout=1");
            exit;
        }
        $timePercentage = min(100, ($timeElapsed / $totalExamSeconds) * 100);
        if (!isset($_SESSION['exam_sessions'][$year]['question_start_times'][$questionNum])) {
            $_SESSION['exam_sessions'][$year]['question_start_times'][$questionNum] = time();
        }
        $questionStartTime = $_SESSION['exam_sessions'][$year]['question_start_times'][$questionNum];
        $timeOnQuestion = time() - $questionStartTime;
        $questionTimeRemaining = max(0, 60 - $timeOnQuestion);
        if ($timeOnQuestion >= 60 && $timeOnQuestion <= 61 && !isset($_SESSION['exam_sessions'][$year]['alarm_sounded'][$questionNum])) {
            $_SESSION['exam_sessions'][$year]['alarm_sounded'][$questionNum] = true;
            $showAlarm = true;
        }
    } elseif ($page === 'exam' && isset($_GET['exam_type']) && $_GET['exam_type'] === 'random' && isset($_GET['exam_id']) && isset($_SESSION['exam_sessions'][$_GET['exam_id']]) && !$_SESSION['exam_sessions'][$_GET['exam_id']]['submitted']) {
        $examActive = true;
        $activeExamId = $_GET['exam_id'];
        $activeExamType = 'random';
        $startTime = $_SESSION['exam_sessions'][$activeExamId]['start_time'];
        $timeElapsed = time() - $startTime;
        $timeRemaining = max(0, $totalExamSeconds - $timeElapsed);
        $answeredCount = count($_SESSION['exam_sessions'][$activeExamId]['answers'] ?? []);
        if ($timeRemaining <= 0 && !$_SESSION['exam_sessions'][$activeExamId]['submitted']) {
            $_SESSION['exam_sessions'][$activeExamId]['submitted'] = true;
            header("Location: ?page=random_results&exam_id=" . urlencode($activeExamId) . "&timeout=1");
            exit;
        }
        $timePercentage = min(100, ($timeElapsed / $totalExamSeconds) * 100);
        if (!isset($_SESSION['exam_sessions'][$activeExamId]['question_start_times'][$questionNum])) {
            $_SESSION['exam_sessions'][$activeExamId]['question_start_times'][$questionNum] = time();
        }
        $questionStartTime = $_SESSION['exam_sessions'][$activeExamId]['question_start_times'][$questionNum];
        $timeOnQuestion = time() - $questionStartTime;
        $questionTimeRemaining = max(0, 60 - $timeOnQuestion);
        if ($timeOnQuestion >= 60 && $timeOnQuestion <= 61 && !isset($_SESSION['exam_sessions'][$activeExamId]['alarm_sounded'][$questionNum])) {
            $_SESSION['exam_sessions'][$activeExamId]['alarm_sounded'][$questionNum] = true;
            $showAlarm = true;
        }
    }
}
