        .table-success { background-color: rgba(40, 167, 69, 0.2) !important; }
        .table-danger { background-color: rgba(220, 53, 69, 0.2) !important; }
        .table-warning { background-color: rgba(255, 193, 7, 0.2) !important; }
        .theme-toggle-btn { background: var(--btn-bg); border: 1px solid var(--border-color); border-radius: 40px; padding: 8px 20px; cursor: pointer; transition: all 0.2s; color: var(--text-primary); font-weight: 500; display: flex; align-items: center; gap: 8px; }
        .theme-toggle-btn:hover { background: var(--btn-hover); transform: scale(1.02); }
        .question-nav-wrapper { max-height: 320px; overflow-y: auto; padding: 5px; border-radius: 8px; }
