        .alarm-flash { animation: alarmFlash 0.5s ease-in-out 3; }
        @keyframes alarmFlash { 0% { opacity: 1; background-color: var(--alert-warning-bg); } 50% { opacity: 0.8; background-color: #ffc107; } 100% { opacity: 1; background-color: var(--alert-warning-bg); } }
        .pulse-btn { animation: pulseButton 1.5s ease-in-out infinite; }
        @keyframes pulseButton { 0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(40, 167, 69, 0.7); } 70% { transform: scale(1.05); box-shadow: 0 0 0 10px rgba(40, 167, 69, 0); } 100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(40, 167, 69, 0); } }
        footer { background-color: var(--footer-bg) !important; border-top: 1px solid var(--border-color); }
        footer p, footer small { color: var(--footer-text) !important; }
        .random-exam-card { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; }
        .random-exam-card .btn { background-color: rgba(255,255,255,0.2); border-color: rgba(255,255,255,0.3); color: white; }
        .random-exam-card .btn:hover { background-color: rgba(255,255,255,0.3); }
        .source-badge { font-size: 0.7rem; opacity: 0.7; }
        .past-exam-card { transition: transform 0.2s; }
        .past-exam-card:hover { transform: translateY(-4px); }
        .modal-content { background-color: var(--bg-card) !important; color: var(--text-primary) !important; border-color: var(--border-color) !important; }
        .modal-header, .modal-footer { background-color: var(--bg-header) !important; border-color: var(--border-color) !important; color: var(--text-primary) !important; }
        .btn-close { filter: var(--btn-close-filter, none); }
        body.dark-mode .btn-close { --btn-close-filter: invert(1); }
        .table tbody tr { cursor: pointer; }
        .table tbody tr:hover { background-color: var(--answer-hover) !important; }
    </style>
</head>
