        $hasImage = isset($currentQuestion['image']) && !empty($currentQuestion['image']);
        ?>
        <div class="d-flex justify-content-between align-items-center mb-4"><div><h2><?= htmlspecialchars($exam['title']) ?></h2><p class="text-muted">Exam Simulation Mode - <?= $answeredCount ?>/100 Answered</p></div><div><a href="?page=howto" class="btn btn-outline-warning me-2" target="_blank"><i class="fas fa-lightbulb me-2"></i>How to Answer</a><a href="?page=home" class="btn btn-outline-secondary"><i class="fas fa-home me-2"></i>Home</a></div></div>
        <div class="row"><div class="col-md-8 mx-auto">
            <div class="card mb-4"><div class="card-body"><div class="row"><div class="col-md-6"><div class="d-flex justify-content-between mb-2"><span class="fw-bold">Total Time Remaining</span><span class="badge bg-primary"><?= $answeredCount ?>/100 Answered</span></div><div class="progress mb-2"><div class="progress-bar bg-success" style="width: <?= $timePercentage ?>%"></div></div><div id="totalTimer" class="timer-large <?= $timeRemaining < 600 ? 'timer-warning' : '' ?>"><?= gmdate("H:i:s", $timeRemaining) ?></div><small class="text-muted">Exam ends at 2 hours</small></div><div class="col-md-6"><div class="d-flex justify-content-between mb-2"><span class="fw-bold">Time on Current Question</span><span class="badge <?= $timeOnQuestion > 60 ? 'bg-warning' : 'bg-info' ?>"><?= $timeOnQuestion > 60 ? 'Over 1 min' : 'Within 1 min' ?></span></div><div class="progress mb-2"><div class="progress-bar <?= $timeOnQuestion > 60 ? 'bg-warning' : 'bg-info' ?>" style="width: <?= min(100, ($timeOnQuestion / 60) * 100) ?>%"></div></div><div id="questionTimer" class="timer-large <?= $timeOnQuestion > 60 ? 'timer-critical' : '' ?>"><?= gmdate("i:s", max(0, 60 - $timeOnQuestion)) ?></div><small class="text-muted">1-minute alert when this reaches 0</small></div></div><?php if ($showAlarm): ?><div class="alert alert-warning alarm-flash mt-2 text-center" id="timeAlert"><i class="fas fa-hourglass-end me-2"></i><strong>1 minute on this question!</strong> Consider moving to the next.</div><script>setTimeout(() => { const alert = document.getElementById('timeAlert'); if(alert) alert.style.display = 'none'; }, 3000);</script><?php endif; ?></div></div>
            
            <div class="card shadow mb-4"><div class="card-header"><h5 class="mb-0">Question <?= $questionNum ?> of 100</h5><small class="text-muted"><i class="fas fa-tag me-1"></i>Category: <?= $questionCategory ?></small></div><div class="card-body"><p class="card-text fs-5 mb-4"><?= nl2br(htmlspecialchars($currentQuestion['text'])) ?></p><?php if ($hasImage): ?><div class="mb-4 p-3 rounded" style="background-color: var(--code-bg);"><pre class="mb-0" style="font-family: monospace; white-space: pre-wrap;"><?= htmlspecialchars($currentQuestion['image']) ?></pre></div><?php endif; ?><form method="post" action="" id="questionForm"><input type="hidden" name="save_answer" value="1"><input type="hidden" name="exam_type" value="past"><input type="hidden" name="year" value="<?= $year ?>"><input type="hidden" name="qnum" value="<?= $questionNum ?>"><input type="hidden" name="redirect" value="?page=past_exam&year=<?= urlencode($year) ?>&mode=practice&q=<?= $questionNum ?>"><div class="mb-4"><?php foreach (['a', 'b', 'c', 'd'] as $opt): $choice = $currentQuestion['choices'][$opt]; $selected = ($savedAnswer === $opt) ? 'selected' : ''; ?><div class="form-check mb-3 p-3 border rounded answer-choice <?= $selected ?>"><input class="form-check-input" type="radio" name="answer" id="opt<?= $opt ?>" value="<?= $opt ?>" <?= $selected ? 'checked' : '' ?> onchange="this.form.submit()"><label class="form-check-label w-100" for="opt<?= $opt ?>"><span class="fw-bold me-2"><?= strtoupper($opt) ?>.</span><?= nl2br(htmlspecialchars($choice)) ?></label></div><?php endforeach; ?></div></form><div class="d-flex justify-content-between mt-4"><?php if ($questionNum > 1): ?><a href="?page=past_exam&year=<?= urlencode($year) ?>&mode=practice&q=<?= $questionNum - 1 ?>" class="btn btn-outline-primary"><i class="fas fa-chevron-left me-2"></i>Previous</a><?php else: ?><span></span><?php endif; ?><?php if ($questionNum < 100): ?><a href="?page=past_exam&year=<?= urlencode($year) ?>&mode=practice&q=<?= $questionNum + 1 ?>" class="btn btn-outline-primary">Next<i class="fas fa-chevron-right ms-2"></i></a><?php else: ?><?php if ($answeredCount == 100 || $timeRemaining <= 0): ?><a href="?action=submit_past_exam&year=<?= urlencode($year) ?>" class="btn btn-success" onclick="return confirm('Submit exam and see your results?')"><i class="fas fa-check-circle me-2"></i>Submit Exam</a><?php else: ?><span class="text-muted">Answer all questions to submit</span><?php endif; ?><?php endif; ?></div></div></div>
            
            <div class="card"><div class="card-header"><h6 class="mb-0"><i class="fas fa-th-large me-2"></i>Quick Question Navigation</h6></div><div class="card-body"><div class="question-nav-wrapper"><div class="question-nav-grid"><?php for ($i = 1; $i <= 100; $i++): $isAnswered = isset($_SESSION['exam_sessions'][$year]['answers'][$i]); $btnClass = 'question-nav-btn'; if ($isAnswered) $btnClass .= ' answered'; elseif (!$isAnswered && $i === $questionNum && $timeOnQuestion > 60) $btnClass .= ' time-warning'; if ($i === $questionNum) $btnClass .= ' current'; ?><a href="?page=past_exam&year=<?= urlencode($year) ?>&mode=practice&q=<?= $i ?>" class="<?= $btnClass ?>" title="<?= $isAnswered ? 'Answered' : 'Not answered' ?>"><?= $i ?></a><?php endfor; ?></div></div><div class="row mt-4 pt-3 border-top"><div class="col-md-6"><div class="progress mb-2" style="height: 10px;"><div class="progress-bar bg-success" style="width: <?= ($answeredCount/100)*100 ?>%"></div></div><div class="small text-muted"><?= $answeredCount ?> completed · <?= 100 - $answeredCount ?> remaining</div></div><div class="col-md-6 text-md-end mt-3 mt-md-0"><?php if ($timeRemaining <= 0): ?><a href="?action=submit_past_exam&year=<?= urlencode($year) ?>" class="btn btn-danger btn-lg"><i class="fas fa-hourglass-end me-2"></i>Time's Up! Submit Now</a><?php elseif ($answeredCount == 100): ?><a href="?action=submit_past_exam&year=<?= urlencode($year) ?>" class="btn btn-success btn-lg pulse-btn"><i class="fas fa-check-circle me-2"></i>Submit Exam</a><?php endif; ?></div></div></div></div>
        </div></div>
        <script>
            let totalTime = <?= $timeRemaining ?>; let questionTime = <?= max(0, 60 - $timeOnQuestion) ?>;
            const totalTimerDisplay = document.getElementById('totalTimer'); const questionTimerDisplay = document.getElementById('questionTimer');
            let alarmTriggered = <?= $showAlarm ? 'true' : 'false' ?>;
            const timer = setInterval(() => { totalTime--; if (totalTimerDisplay) { let h = Math.floor(totalTime / 3600); let m = Math.floor((totalTime % 3600) / 60); let s = totalTime % 60; totalTimerDisplay.textContent = String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ':' + String(s).padStart(2,'0'); } <?php if (!$savedAnswer): ?> questionTime--; if (questionTimerDisplay && questionTime >= 0) { let qm = Math.floor(questionTime / 60); let qs = questionTime % 60; questionTimerDisplay.textContent = String(qm).padStart(2,'0') + ':' + String(qs).padStart(2,'0'); } if (questionTime <= 0 && !alarmTriggered) { alarmTriggered = true; if (questionTimerDisplay) questionTimerDisplay.classList.add('timer-critical'); } <?php endif; ?> if (totalTime <= 0) { clearInterval(timer); window.location.href = '?action=submit_past_exam&year=<?= urlencode($year) ?>&timeout=1'; } }, 1000);
        </script>

    <?php elseif ($page === 'past_results' && $year && isset($exams[$year]) && isset($_SESSION['exam_sessions'][$year])): 
        $exam = $exams[$year]; $session = $_SESSION['exam_sessions'][$year]; $answers = $session['answers'] ?? []; $timeSpent = time() - $session['start_time']; $timeSpentFormatted = gmdate("H:i:s", min($timeSpent, 7200));
        $correct = $incorrect = $unanswered = 0; $results = []; $categoryPerformance = [];
        for ($i = 1; $i <= 100; $i++) { $userAnswer = $answers[$i] ?? null; $correctAnswer = $exam['answer_key'][$i]; $category = getQuestionCategory($exam['questions'][$i]['text']); if (!isset($categoryPerformance[$category])) { $categoryPerformance[$category] = ['correct' => 0, 'total' => 0]; } $categoryPerformance[$category]['total']++; if (!$userAnswer) { $unanswered++; $results[$i] = ['status' => 'unanswered', 'user' => null, 'correct' => $correctAnswer, 'category' => $category]; } elseif ($userAnswer === $correctAnswer) { $correct++; $categoryPerformance[$category]['correct']++; $results[$i] = ['status' => 'correct', 'user' => $userAnswer, 'correct' => $correctAnswer, 'category' => $category]; } else { $incorrect++; $results[$i] = ['status' => 'incorrect', 'user' => $userAnswer, 'correct' => $correctAnswer, 'category' => $category]; } } $score = round(($correct / 100) * 100); $passing = $score >= 60;
        ?>
        <div class="d-flex justify-content-between align-items-center mb-4"><h2><?= htmlspecialchars($exam['title']) ?> - Results</h2><div><a href="?page=home" class="btn btn-outline-secondary me-2"><i class="fas fa-home me-2"></i>Home</a><a href="?reset_past_exam=1&year=<?= urlencode($year) ?>" class="btn btn-primary" onclick="return confirm('Start a new exam?')"><i class="fas fa-redo-alt me-2"></i>New Exam</a></div></div>
        <div class="row mb-4"><div class="col-md-3 mb-3"><div class="card text-center h-100 bg-primary text-white"><div class="card-body"><h3><?= $score ?>%</h3><p class="mb-0">Final Score</p><?php if ($passing): ?><small>PASSED</small><?php else: ?><small>NOT PASSED</small><?php endif; ?></div></div></div><div class="col-md-3 mb-3"><div class="card text-center h-100 bg-success text-white"><div class="card-body"><h3><?= $correct ?></h3><p class="mb-0">Correct</p></div></div></div><div class="col-md-3 mb-3"><div class="card text-center h-100 bg-danger text-white"><div class="card-body"><h3><?= $incorrect ?></h3><p class="mb-0">Incorrect</p></div></div></div><div class="col-md-3 mb-3"><div class="card text-center h-100 bg-warning text-dark"><div class="card-body"><h3><?= $unanswered ?></h3><p class="mb-0">Unanswered</p></div></div></div></div>
        <div class="row mb-4"><div class="col-md-6"><div class="card"><div class="card-header"><h5 class="mb-0">Exam Statistics</h5></div><div class="card-body"><table class="table table-borderless"><tr><th>Time Spent:</th><td class="fw-bold"><?= $timeSpentFormatted ?></td></tr><tr><th>Total Questions:</th><td class="fw-bold">100</td></tr><tr><th>Result:</th><td class="fw-bold"><?= $passing ? '<span class="text-success">PASSED</span>' : '<span class="text-danger">FAILED</span>' ?></td></tr><tr><th>Score:</th><td class="fw-bold"><?= $score ?>%</td></tr></table></div></div></div><div class="col-md-6"><div class="card"><div class="card-header"><h5 class="mb-0">Performance by Category</h5></div><div class="card-body"><?php foreach ($categoryPerformance as $category => $perf): $percentage = round(($perf['correct'] / $perf['total']) * 100); ?><div class="mb-3"><div class="d-flex justify-content-between"><span><?= $category ?></span><span><?= $perf['correct'] ?>/<?= $perf['total'] ?> (<?= $percentage ?>%)</span></div><div class="progress" style="height: 8px;"><div class="progress-bar bg-<?= $percentage >= 70 ? 'success' : ($percentage >= 50 ? 'warning' : 'danger') ?>" style="width: <?= $percentage ?>%"></div></div></div><?php endforeach; ?></div></div></div></div>
        
