e=exam&exam_type=random&exam_id=<?= urlencode($examId) ?>&mode=practice&q=<?= $questionNum + 1 ?>" class="btn btn-outline-primary">Next<i class="fas fa-chevron-right ms-2"></i></a><?php else: ?><?php if ($answeredCount == 100 || $timeRemaining <= 0): ?><a href="?action=submit_random_exam&exam_id=<?= urlencode($examId) ?>" class="btn btn-success" onclick="return confirm('Submit exam and see your results?')"><i class="fas fa-check-circle me-2"></i>Submit Exam</a><?php else: ?><span class="text-muted">Answer all questions to submit</span><?php endif; ?><?php endif; ?></div></div></div>
                
