<!-- Question Detail Modal -->
<div class="modal fade" id="questionModal" tabindex="-1" aria-labelledby="questionModalLabel" aria-hidden="true">
    <div class="modal-dialog modal-lg modal-dialog-scrollable">
        <div class="modal-content">
            <div class="modal-header"><h5 class="modal-title" id="questionModalLabel">Question Review</h5><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button></div>
            <div class="modal-body" id="questionModalBody"></div>
            <div class="modal-footer"><button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Close</button></div>
        </div>
    </div>
</div>

<footer class="py-4 mt-5"><div class="container"><div class="row"><div class="col-md-6"><p class="mb-0">&copy; IT Passport Examination Simulator</p><small class="text-muted">Based on official past exams (2022-2025) | Random Generator Available</small></div><div class="col-md-6 text-end"><a href="?action=generate_random_exam" class="me-3"><i class="fas fa-random me-1"></i>Generate Random Exam</a><p class="mb-0 mt-2">Exam Time: 2 Hours Total | 1-Minute Question Alerts</p></div></div></div></footer>

<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0-alpha1/dist/js/bootstrap.bundle.min.js"></script>
<script>
    const themeToggle = document.getElementById('themeToggle');
    if (themeToggle) { themeToggle.addEventListener('click', function() { window.location.href = '?toggle_theme=1'; }); }
    if (!document.cookie.includes('theme_preference') && !<?= isset($_SESSION['theme_preference']) ? 'true' : 'false' ?>) { const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches; if (prefersDark) { window.location.href = '?toggle_theme=1'; } }
    
    function escapeHtml(text) { if (!text) return ''; const div = document.createElement('div'); div.textContent = text; return div.innerHTML; }
    
    function showQuestionModalPast(qNum, questionText, choices, correctAnswer, userAnswer, status, imageData, solutionData) {
        const modalBody = document.getElementById('questionModalBody');
        let solution = solutionData && typeof solutionData === 'object' ? solutionData : null;
        let solutionHtml = '';
        if (solution && solution.explanation) {
            let stepsHtml = solution.steps ? `<h6><i class="fas fa-list-ol me-2"></i>Step-by-Step:</h6><ol>${solution.steps.map(s => `<li>${escapeHtml(s)}</li>`).join('')}</ol>` : '';
            let conceptsHtml = solution.key_concepts ? `<h6><i class="fas fa-tags me-2"></i>Key Concepts:</h6><div class="mb-2">${solution.key_concepts.map(k => `<span class="badge bg-primary me-1">${escapeHtml(k)}</span>`).join('')}</div>` : '';
            let difficultyHtml = solution.difficulty ? `<h6><i class="fas fa-chart-line me-2"></i>Difficulty:</h6><p>${escapeHtml(solution.difficulty)}</p>` : '';
            solutionHtml = `<div class="alert alert-info mt-3"><h6><i class="fas fa-lightbulb me-2"></i>Solution Explanation</h6><p>${escapeHtml(solution.explanation)}</p>${stepsHtml}${conceptsHtml}${difficultyHtml}</div>`;
        }
        let choicesHtml = '';
        const choiceLetters = ['a', 'b', 'c', 'd'];
        for (let i = 0; i < choiceLetters.length; i++) { const letter = choiceLetters[i]; const choiceText = choices[letter] || ''; const isCorrect = (letter.toUpperCase() === String(correctAnswer).toUpperCase()); const isUserAnswer = (userAnswer && userAnswer.toLowerCase() === letter.toLowerCase()); let choiceClass = ''; let indicator = ''; if (isCorrect) { choiceClass = 'border-success bg-success bg-opacity-10'; indicator = '<i class="fas fa-check-circle text-success me-2"></i>'; } if (isUserAnswer && !isCorrect) { choiceClass = 'border-danger bg-danger bg-opacity-10'; indicator = '<i class="fas fa-times-circle text-danger me-2"></i>'; } choicesHtml += `<div class="p-3 mb-2 border rounded ${choiceClass}"><div class="d-flex align-items-start"><div class="flex-shrink-0 me-3"><span class="fw-bold fs-5">${letter.toUpperCase()}.</span></div><div class="flex-grow-1">${indicator} ${escapeHtml(choiceText)}${isUserAnswer ? `<div class="small mt-1 text-muted"><i class="fas fa-user me-1"></i>Your answer</div>` : ''}${isCorrect && !isUserAnswer ? `<div class="small mt-1 text-success"><i class="fas fa-check me-1"></i>Correct answer</div>` : ''}</div></div></div>`; }
        let statusBadge = status === 'correct' ? '<span class="badge bg-success"><i class="fas fa-check-circle me-1"></i>Correct</span>' : (status === 'incorrect' ? '<span class="badge bg-danger"><i class="fas fa-times-circle me-1"></i>Incorrect</span>' : '<span class="badge bg-warning text-dark"><i class="fas fa-question-circle me-1"></i>Unanswered</span>');
        let imageHtml = (imageData && String(imageData).trim() !== '' && String(imageData) !== 'null') ? `<div class="mb-4"><h6><i class="fas fa-image me-2"></i>Diagram/Figure:</h6><div class="p-3 rounded" style="background-color: var(--code-bg);"><pre class="mb-0" style="font-family: monospace; white-space: pre-wrap;">${escapeHtml(String(imageData))}</pre></div></div>` : '';
        modalBody.innerHTML = `<div class="mb-4"><div class="d-flex justify-content-between align-items-center mb-3"><h4>Question ${escapeHtml(String(qNum))}</h4>${statusBadge}</div><div class="alert alert-secondary"><strong>Your Answer:</strong> ${userAnswer ? String(userAnswer).toUpperCase() : 'Not answered'} &nbsp;&nbsp;|&nbsp;&nbsp;<strong>Correct Answer:</strong> ${String(correctAnswer).toUpperCase()}</div></div><div class="mb-4"><h6><i class="fas fa-question-circle me-2"></i>Question:</h6><div class="p-3 rounded" style="background-color: var(--bg-header);">${escapeHtml(String(questionText))}</div></div>${imageHtml}<div class="mb-4"><h6><i class="fas fa-list-ul me-2"></i>Answer Choices:</h6>${choicesHtml}</div>${solutionHtml}`;
        new bootstrap.Modal(document.getElementById('questionModal')).show();
    }
    
    function showQuestionModalRandom(qNum, questionText, choices, correctAnswer, userAnswer, status, imageData, solutionData, sourceYear, sourceQNum) {
        const modalBody = document.getElementById('questionModalBody');
        let solution = solutionData && typeof solutionData === 'object' ? solutionData : null;
        let solutionHtml = '';
        if (solution && solution.explanation) {
            let stepsHtml = solution.steps ? `<h6><i class="fas fa-list-ol me-2"></i>Step-by-Step:</h6><ol>${solution.steps.map(s => `<li>${escapeHtml(s)}</li>`).join('')}</ol>` : '';
            let conceptsHtml = solution.key_concepts ? `<h6><i class="fas fa-tags me-2"></i>Key Concepts:</h6><div class="mb-2">${solution.key_concepts.map(k => `<span class="badge bg-primary me-1">${escapeHtml(k)}</span>`).join('')}</div>` : '';
            let difficultyHtml = solution.difficulty ? `<h6><i class="fas fa-chart-line me-2"></i>Difficulty:</h6><p>${escapeHtml(solution.difficulty)}</p>` : '';
            solutionHtml = `<div class="alert alert-info mt-3"><div class="mb-2"><strong>Source:</strong> ${escapeHtml(String(sourceYear))} Question ${escapeHtml(String(sourceQNum))}</div><h6><i class="fas fa-lightbulb me-2"></i>Solution Explanation</h6><p>${escapeHtml(solution.explanation)}</p>${stepsHtml}${conceptsHtml}${difficultyHtml}</div>`;
        } else {
            solutionHtml = `<div class="alert alert-info mt-3"><div class="mb-2"><strong>Source:</strong> ${escapeHtml(String(sourceYear))} Question ${escapeHtml(String(sourceQNum))}</div><p>Solution explanation not available for this question.</p></div>`;
        }
        let choicesHtml = '';
        const choiceLetters = ['a', 'b', 'c', 'd'];
        for (let i = 0; i < choiceLetters.length; i++) { const letter = choiceLetters[i]; const choiceText = choices[letter] || ''; const isCorrect = (letter.toUpperCase() === String(correctAnswer).toUpperCase()); const isUserAnswer = (userAnswer && userAnswer.toLowerCase() === letter.toLowerCase()); let choiceClass = ''; let indicator = ''; if (isCorrect) { choiceClass = 'border-success bg-success bg-opacity-10'; indicator = '<i class="fas fa-check-circle text-success me-2"></i>'; } if (isUserAnswer && !isCorrect) { choiceClass = 'border-danger bg-danger bg-opacity-10'; indicator = '<i class="fas fa-times-circle text-danger me-2"></i>'; } choicesHtml += `<div class="p-3 mb-2 border rounded ${choiceClass}"><div class="d-flex align-items-start"><div class="flex-shrink-0 me-3"><span class="fw-bold fs-5">${letter.toUpperCase()}.</span></div><div class="flex-grow-1">${indicator} ${escapeHtml(choiceText)}${isUserAnswer ? `<div class="small mt-1 text-muted"><i class="fas fa-user me-1"></i>Your answer</div>` : ''}${isCorrect && !isUserAnswer ? `<div class="small mt-1 text-success"><i class="fas fa-check me-1"></i>Correct answer</div>` : ''}</div></div></div>`; }
        let statusBadge = status === 'correct' ? '<span class="badge bg-success"><i class="fas fa-check-circle me-1"></i>Correct</span>' : (status === 'incorrect' ? '<span class="badge bg-danger"><i class="fas fa-times-circle me-1"></i>Incorrect</span>' : '<span class="badge bg-warning text-dark"><i class="fas fa-question-circle me-1"></i>Unanswered</span>');
        let imageHtml = (imageData && String(imageData).trim() !== '' && String(imageData) !== 'null') ? `<div class="mb-4"><h6><i class="fas fa-image me-2"></i>Diagram/Figure:</h6><div class="p-3 rounded" style="background-color: var(--code-bg);"><pre class="mb-0" style="font-family: monospace; white-space: pre-wrap;">${escapeHtml(String(imageData))}</pre></div></div>` : '';
        modalBody.innerHTML = `<div class="mb-4"><div class="d-flex justify-content-between align-items-center mb-3"><h4>Question ${escapeHtml(String(qNum))}</h4>${statusBadge}</div><div class="alert alert-secondary"><strong>Your Answer:</strong> ${userAnswer ? String(userAnswer).toUpperCase() : 'Not answered'} &nbsp;&nbsp;|&nbsp;&nbsp;<strong>Correct Answer:</strong> ${String(correctAnswer).toUpperCase()}</div></div><div class="mb-4"><h6><i class="fas fa-question-circle me-2"></i>Question:</h6><div class="p-3 rounded" style="background-color: var(--bg-header);">${escapeHtml(String(questionText))}</div></div>${imageHtml}<div class="mb-4"><h6><i class="fas fa-list-ul me-2"></i>Answer Choices:</h6>${choicesHtml}</div>${solutionHtml}`;
        new bootstrap.Modal(document.getElementById('questionModal')).show();
    }
</script>
</body>
</html>
